import React, { useEffect } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const App = () => {
  const navigation = useNavigation();

  useEffect(() => {
    const handleDeepLink = (event) => {
      if (event.url) {
        const url = new URL(event.url);
        const pathSegments = url.pathname.split('/').filter(segment => segment);

        switch (pathSegments[0]) {
          case 'profile':
            if (pathSegments.length === 2 && !isNaN(pathSegments[1])) {
              navigation.navigate('Profile', { userId: parseInt(pathSegments[1], 10) });
            } else {
              Alert.alert('Invalid URL', 'Please provide a valid profile ID.');
            }
            break;
          case 'payment':
            if (pathSegments.length === 2 && pathSegments[1] === 'confirm') {
              navigation.navigate('PaymentConfirmation');
            } else {
              Alert.alert('Invalid URL', 'Please provide a valid payment confirmation link.');
            }
            break;
          default:
            Alert.alert('Unknown Route', 'The provided URL leads to an unknown route.');
        }
      }
    };

    Linking.addEventListener('url', handleDeepLink);

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, [navigation]);

  useEffect(() => {
    const checkInitialURL = async () => {
      const initialURL = await Linking.getInitialURL();
      if (initialURL) {
        handleDeepLink({ url: initialURL });
      }
    };

    checkInitialURL();
  }, []);

  return (
    <></>
  );
};

export default App;